alter table public.owners add column if not exists expense_plan_enabled boolean not null default true;
create table if not exists public.expense_plan_settings(owner_id uuid primary key references auth.users(id) on delete cascade,tapioca_income numeric(14,2) not null default 0,monthly_fuel numeric(14,2) not null default 0,initial_reserve numeric(14,2) not null default 0,minimum_reserve numeric(14,2) not null default 0,delivery_hours_week numeric(6,2) not null default 0,delivery_net_hour numeric(8,2) not null default 0,exit_date date,updated_at timestamptz not null default now());
create table if not exists public.expense_plan_items(id uuid primary key default gen_random_uuid(),owner_id uuid not null references auth.users(id) on delete cascade,name text not null,creditor text not null default 'Cartão',installment_amount numeric(14,2) not null check(installment_amount>0),current_installment integer not null check(current_installment>0),total_installments integer not null check(total_installments>=current_installment),status text not null default 'active' check(status in('active','paid','deleted')),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create index if not exists expense_plan_items_owner_idx on public.expense_plan_items(owner_id,status);
alter table public.expense_plan_settings enable row level security;alter table public.expense_plan_items enable row level security;
create policy expense_plan_settings_owner_all on public.expense_plan_settings for all to authenticated using((select auth.uid())=owner_id) with check((select auth.uid())=owner_id);
create policy expense_plan_items_owner_all on public.expense_plan_items for all to authenticated using((select auth.uid())=owner_id) with check((select auth.uid())=owner_id);
create policy require_named_user_mfa on public.expense_plan_settings as restrictive for all to authenticated using(coalesce((select auth.jwt())->>'is_anonymous','false')='false' and(select auth.jwt())->>'aal'='aal2') with check(coalesce((select auth.jwt())->>'is_anonymous','false')='false' and(select auth.jwt())->>'aal'='aal2');
create policy require_named_user_mfa on public.expense_plan_items as restrictive for all to authenticated using(coalesce((select auth.jwt())->>'is_anonymous','false')='false' and(select auth.jwt())->>'aal'='aal2') with check(coalesce((select auth.jwt())->>'is_anonymous','false')='false' and(select auth.jwt())->>'aal'='aal2');
grant select,insert,update,delete on public.expense_plan_settings,public.expense_plan_items to authenticated;
create trigger finance_audit_immutable after insert or update or delete on public.expense_plan_settings for each row execute function private.write_finance_audit();
create trigger finance_audit_immutable after insert or update or delete on public.expense_plan_items for each row execute function private.write_finance_audit();
